import{c as e}from"./app.8935f5f1.js";const o={},d=e('<h2 id="ssh远程" tabindex="-1"><a class="header-anchor" href="#ssh远程" aria-hidden="true">#</a> ssh远程</h2><ul><li><p>第一种情况（没做端口映射） 命令： <code>ssh 用户名@主机ip 端口号</code></p></li><li><p>例子： 比如要远程到主机<code>22.22.22.22的12345</code>端口，命令为 <code>ssh root@22.22.22.22 12345</code></p></li><li><p>第二种情况（做了端口映射） 命令： <code>ssh 用户名@主机ip -p 映射的端口号</code></p></li></ul><p>例子： 比如要远程到主机<code>22.22.22.22的12345端口</code>，但是<code>12345端口被映射到了54321端口</code>，所以要访问12345端口的命令为 <code>ssh root@22.22.22.22 -p 54321 </code></p>',3);o.render=function(e,o){return d};export{o as default};
